blocks.body:
{
    "level": "A1",
    "intro": "W tym temacie nauczysz się <strong>zaimków osobowych i dopełnienia</strong>, czyli dwóch głównych form, które pokazują, kto i kto wykonuje czynność. otrzymuje.",
    "rules": [
        {
            "label": "Temat",
            "color": "emerald",
            "text": "<strong>Zaimki podmiotowe</strong> – kto działa:",
            "example": "Pracuję. Ona czyta. Grają."
        },
        {
            "label": "Obiekt",
            "color": "blue",
            "text": "<strong>Zaimki dopełnienia</strong> – kto/co:",
            "example": "Zadzwoń do mnie. Widzę go. Powiedz nam."
        },
        {
            "label": "Pozycja",
            "color": "amber",
            "text": "<strong>Pozycja w zdaniu</strong>:",
            "example": "Podmiot przed czasownikiem, dopełnienie po."
        }
    ]
}

{
    "title": "1. Dwie formy zaimków osobowych według czasownika)",
    "intro": "Особові займенники мають дві форми залежно від їхньої ролі у реченні:",
    "items": [
        {
            "label": "Subject",
            "title": "Підметові",
            "subtitle": "I, you, he, she, it, we, they — виконують дію (перед дієсловом)"
        },
        {
            "label": "Obiekt",
            "title": "Obiekt",
            "subtitle": "ja, ty, on, ona, ono, my, oni — otrzymują akcję (po czasowniku)"
        }
    ]
}

{
    "title": "2. Zaimki podmiotowe – zaimki podmiotowe",
    "sections": [
        {
            "label": "Co to są zaimki podmiotowe?",
            "color": "emerald",
            "description": "Zaimki podmiotowe są używane jako <strong>podmiot w zdaniu</strong> – pokazują, kto wykonuje czynność. Stań <strong>przed czasownikiem</strong>.",
            "examples": [
                {
                    "en": "I work every day.",
                    "ua": "Я працюю щодня."
                },
                {
                    "en": "You are smart.",
                    "ua": "Ти розумний / Ви розумні."
                },
                {
                    "en": "He lives in Kyiv.",
                    "ua": "Він живе в Києві."
                },
                {
                    "en": "She speaks English.",
                    "ua": "Ona mówi po angielsku."
                },
                {
                    "en": "To jest kot.",
                    "ua": "To jest kot."
                },
                {
                    "en": "Uczymy się razem.",
                    "ua": "Uczymy się razem."
                },
                {
                    "en": "Bawią się piłka nożna.",
                    "ua": " piłka nożna."
                }
            ]
        },
        {
            "label": "Ja to ja",
            "color": "sky",
            "description": "<strong>Ja</strong> (ja) jest zawsze pisane wielką literą, nawet w zdaniu.",
            "examples": [
                {
                    "en": "Lubię kawę.",
                    "ua": "Uwielbiam kawa."
                },
                {
                    "en": "Mój przyjaciel i ja poszliśmy do parku.",
                    "ua": "Mój przyjaciel i ja poszliśmy do parku."
                },
                {
                    "en": "Jestem studentem.",
                    "ua": "Jestem studentem."
                }
            ],
            "note": "📌 Zawsze ja (wielka litera), nigdy i (małe litery)!"
        },
        {
            "label": "Jesteś ty / вы",
            "color": "purple",
            "description": "<strong>Ty</strong> (ty/ty) to uniwersalna forma określająca adres w liczbie pojedynczej i mnogiej, formalną i nieformalną.",
            "examples": [
                {
                    "en": "Jesteś moim przyjacielem. (ty)",
                    "ua": "Jesteś moim przyjacielem."
                },
                {
                    "en": "Jesteś tu mile widziany. (ty)",
                    "ua": "Jesteś tu zawsze mile widziany."
                },
                {
                    "en": "Czy jesteś gotowy?",
                    "ua": "Jesteś gotowy? Czy jesteś gotowy?"
                }
            ]
        },
        {
            "label": "He, She, It — він, вона, воно",
            "color": "amber",
            "description": "<strong>He</strong> — чоловічий рід, <strong>she</strong> — жіночий рід, <strong>it</strong> — для тварин, предметів, абстрактних понять.",
            "examples": [
                {
                    "en": "He is my brother.",
                    "ua": "Він мій брат."
                },
                {
                    "en": "Pracuje w banku. (pies → on), pogoda, czas, dystans.",
                    "ua": "Вона працює в банку."
                },
                {
                    "en": "It is raining.",
                    "ua": "Йде дощ."
                },
                {
                    "en": "It is a good book.",
                    "ua": "Це хороша книга."
                }
            ],
            "note": "📌 It використовуємо для тварин (the dog → it), погоди, часу, відстані."
        },
        {
            "label": "My, Oni – my, oni",
            "color": "rose",
            "description": "<strong>My</strong> (my) to grupa, do której zaliczam się ja. <strong>Oni</strong> (oni) to grupa, w której nie ma mnie.",
            "examples": [
                {
                    "en": "Kochamy to miasto.",
                    "ua": "Kochamy to miasto."
                },
                {
                    "en": "To są studenci.",
                    "ua": "To są studenci."
                },
                {
                    "en": "Chodzimy do szkoły razem.",
                    "ua": "Chodzimy razem do szkoły."
                },
                {
                    "en": "Mieszkają w Londynie.",
                    "ua": "Mieszkają w Londynie."
                }
            ]
        }
    ]
}

{
    "title": "3. Zaimki dopełnienia - Zaimki dopełnienia",
    "sections": [
        {
            "label": "Co to są zaimki dopełnienia?",
            "color": "blue",
            "description": "Zaimki dopełnienia są używane jako <strong>dodatek</strong> - pokazują do kogo/do czego skierowana jest akcja. Stań <strong>po czasowniku lub przyimku</strong>.",
            "examples": [
                {
                    "en": "Zadzwoń do mnie później.",
                    "ua": "Zadzwoń później."
                },
                {
                    "en": "Widzę cię.",
                    "ua": "Widzę cię/ty."
                },
                {
                    "en": "Ona kocha niego.",
                    "ua": "Ona go kocha."
                },
                {
                    "en": "Powiedz jej prawdę.",
                    "ua": "Powiedz jej prawdę."
                },
                {
                    "en": "Daj mi to.",
                    "ua": "Daj to ja."
                },
                {
                    "en": "Zaprosili nas.",
                    "ua": " nas."
                },
                {
                    "en": "Znam ich dobrze.",
                    "ua": "Znam ich dobrze."
                }
            ]
        },
        {
            "label": "Po czasownikach",
            "color": "sky",
            "description": "Zaimki dopełnienia pojawiają się po czasowniku jako dopełnienie bezpośrednie lub pośrednie.",
            "examples": [
                {
                    "en": "Lubię go.",
                    "ua": "On lubi mnie."
                },
                {
                    "en": "Pomóż mi, proszę.",
                    "ua": "Pomóż mi, proszę."
                },
                {
                    "en": "Ona nas zna.",
                    "ua": "Ona nas zna."
                },
                {
                    "en": "Powiedziałem im wszystko.",
                    "ua": "Powiedziałem im wszystko."
                }
            ]
        },
        {
            "label": "Po przyimkach",
            "color": "purple",
            "description": "Po przyimkach (with, for, to, about, at itp.) zawsze używamy zaimków dopełnienia</strong>.",
            "examples": [
                {
                    "en": "Chodź ze mną.",
                    "ua": "Chodź ze mną."
                },
                {
                    "en": "To jest dla ciebie.",
                    "ua": "To jest dla ciebie / ty."
                },
                {
                    "en": "Porozmawiaj z nim.",
                    "ua": "Porozmawiaj z nim."
                },
                {
                    "en": "Ona myśli o niej.",
                    "ua": "Ona myśli o niej."
                },
                {
                    "en": "Patrzą na nas.",
                    "ua": "Patrzą na nas."
                }
            ],
            "note": "📌Nigdy nie mówię z,dla,do — zawsze ja!"
        },
        {
            "label": "W krótkich odpowiedziach",
            "color": "amber",
            "description": "W krótkich odpowiedziach używamy <strong>obiektu zaimki</strong>.",
            "examples": [
                {
                    "en": "Kto to zrobił? - Ja. (nie ja!)",
                    "ua": "Kto to zrobił? — I."
                },
                {
                    "en": "Kto ma ochotę na kawę? - Ja! (mówione)",
                    "ua": "Kto ma ochotę na kawę? — Ja!"
                },
                {
                    "en": "Z kim ona rozmawia? — On.",
                    "ua": "Z kim ona rozmawia? — Z nim."
                }
            ],
            "note": "📌 Formalnie poprawne: To ja / To był on. Ale potocznie: To ja / To był on."
        }
    ]
}

{
    "title": "4. Tabela porównawcza: podmiot kontra przedmiot",
    "intro": "Pełna tabela zaimków osobowych w dwóch formach:",
    "rows": [
        {
            "en": "Ja",
            "ua": "ja (temat)",
            "note": "ja — ja, ja (dodatek)"
        },
        {
            "en": "ty[[CODX_SEG_5]]ty ty (temat)",
            "ua": "ти/ви (підмет)",
            "note": "ty — ty (dodatek)"
        },
        {
            "en": "on",
            "ua": "on (temat)",
            "note": "on jest jego, on (dodatek)"
        },
        {
            "en": "ona",
            "ua": "ona (temat)",
            "note": "ona to ona, ona (dodatek)"
        },
        {
            "en": "to[[CODX_SEG_14]]]to (temat)",
            "ua": "воно (підмет)",
            "note": "to jego/ona (załącznik)"
        },
        {
            "en": "my",
            "ua": "my (temat)",
            "note": "my to my (załącznik)"
        },
        {
            "en": "oni[[CODX_SEG_20]]]oni (temat)",
            "ua": "вони (підмет)",
            "note": "oni — oni, oni (dodatek)"
        }
    ],
    "warning": "📌 Ty i ono mają tę samą formę co podmiot i jako dodatek!"
}

{
    "title": "5. Jak decydujesz, którego formularza użyć?",
    "sections": [
        {
            "label": "Zadaj pytanie: Kto? Co? (Kto dzwonił? - On)",
            "color": "emerald",
            "description": "Якщо можна запитати <strong>Хто?</strong> або <strong>Що?</strong> (підмет) — використовуй subject pronoun.",
            "examples": [
                {
                    "en": "He called. (Хто подзвонив? — Він)",
                    "ua": "Zadzwonił."
                },
                {
                    "en": "Ona tu jest. (Kto tu jest? - Ona)",
                    "ua": "Ona tu jest."
                },
                {
                    "en": "Wygrali. (Kto wygrał? - Oni)",
                    "ua": "Wygrali."
                }
            ]
        },
        {
            "label": "Zapytaj: Kto? Kogo? Co?",
            "color": "blue",
            "description": "Jeśli mogę zapytać <strong>Kto? Kogo? Co?</strong> (dodatek) — użyj zaimka dopełnienia.",
            "examples": [
                {
                    "en": "Zadzwonił do mnie. (Kto dzwonił? - Ja)",
                    "ua": "Zadzwonił do mnie."
                },
                {
                    "en": "Widzę ją. (Kogo widzę? - Ją)",
                    "ua": "Widzę ją."
                },
                {
                    "en": "Powiedz im. (Komu powiedzieć? — Im)",
                    "ua": "Powiedz im."
                }
            ]
        },
        {
            "label": "Pozycja zdania",
            "color": "amber",
            "description": "<strong>Przed czasownikiem</strong> — podmiot, <strong>po czasowniku/przyimek</strong> — dopełnienie.",
            "examples": [
                {
                    "en": "Lubię go. (nie On jak ja)",
                    "ua": "Я → temat, on → przedmiot"
                },
                {
                    "en": "Ona nam pomaga. (nie Jej pomagamy)",
                    "ua": "Ona → podmiot, my → przedmiot"
                },
                {
                    "en": "Oni mnie znają. (nie oni wiedzą ja)",
                    "ua": "Oni → podmiot, ja → przedmiot"
                }
            ],
            "note": "📌 W razie wątpliwości pomyśl o pozycji w zdaniu!"
        }
    ]
}

{
    "title": "6. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomieszanie form podmiotu i dopełnienia.",
            "wrong": "Ja i John poszliśmy do parku. / Ona jest moją przyjaciółką.",
            "right": " ✅ <span class="font-mono">John i ja poszliśmy do parku. Ona jest moją przyjaciółką. / To jest dla niego.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Subject після прийменника.",
            "wrong": "Come with I. / This is for he.",
            "right": "✅ <span class="font-mono">Come with me. / This is for him.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Dopełnienie przed czasownikiem.",
            "wrong": "On lubi pizzę. / To są studenci.",
            "right": "​​​​ <span class="font-mono">Lubi pizzę. / To są uczniowie.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Ja z małą literą.",
            "wrong": "Wczoraj poszedłem do szkoły.",
            "right": "​​​​ <span class="font-mono">Wczoraj poszedłem do szkoły szkoła.</span>"
        }
    ]
}

{
    "title": "8. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwy zaimek",
    "select_intro": "Wpisz w puste miejsca właściwy zaimek (podmiot lub dopełnienie).",
    "selects": [
        {
            "label": "___ jestem uczniem. (Ja / ja)",
            "prompt": "Jaki zaimek?"
        },
        {
            "label": "Zadzwoń ___ później. (Ja / ja)",
            "prompt": "Jaki jest zaimek?"
        },
        {
            "label": "___ jest moim przyjacielem. (Ona / Ona)",
            "prompt": "Jaki zaimek?"
        },
        {
            "label": "Chodź z ___. (my / nas)",
            "prompt": "Jaki jest zaimek?"
        },
        {
            "label": "___ jak pizza. (Oni / Oni)",
            "prompt": "Co zaimek?"
        }
    ],
    "options": [
        "Ja",
        "ja",
        "on[[CODX_SEG_23]]]jego",
        "him",
        "ona[[CODX_SEG_24]]] SEG_25]]]jej",
        "her",
        "my",
        "nas",
        "oni",
        "oni"
    ],
    "input_title": "Ćwiczenie 2. Wypełnij spacje",
    "input_intro": "Wpisz poprawny zaimek.",
    "inputs": [
        {
            "before": "___ pracuję każdego dnia. (pracuję)",
            "after": " →"
        },
        {
            "before": "Powiedz ___ prawdę. (powiedz jej)",
            "after": "→"
        },
        {
            "before": "___ są przyjaciółmi. (jesteśmy przyjaciółmi)",
            "after": "→"
        },
        {
            "before": "Wiem ___. (Znam je)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd z zaimkami.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Ja jak lód krem.",
            "example_target": "Lubię lody."
        },
        {
            "original": "1. Ona jest moją siostrą.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Chodź z I.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. oni są studentami. - Formy dzierżawcze",
            "placeholder": "Виправ помилку"
        }
    ]
}

{
    "title": "Інші сторінки з категорії Займенники та вказівні слова",
    "items": [
        {
            "label": "Pronouns — Займенники (огляд)",
            "current": false
        },
        {
            "label": "Personal & Object Pronouns — Особові й об'єктні",
            "current": true
        },
        {
            "label": "Possessive Forms — Присвійні форми",
            "current": false
        },
        {
            "label": "Zaimki zwrotne - Zaimki zwrotne",
            "current": false
        }
    ]
}
